contracts/SmartAccount.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title VoterSmartAccount
 * @author Katoh Thesis Project
 * @notice A minimal ERC-4337-style Smart Account for student voters.
 * @dev Each student gets a Smart Account deployed/resolved from their DID.
 *      The account:
 *      - Is controlled by the student's DID (derived from biometric + matric number)
 *      - Can execute calls to the Voting contract
 *      - Does not require the student to hold private keys or ETH
 *
 *      This is a simplified implementation for the thesis prototype.
 */
contract VoterSmartAccount is Ownable {
    /// @notice The DID hash associated with this account
    bytes32 public didHash;

    /// @notice Whether this account has been initialized
    bool public initialized;

    // -------------------------------------------------------
    // Events
    // -------------------------------------------------------

    event AccountInitialized(bytes32 indexed didHash, address indexed owner);
    event Executed(address indexed target, uint256 value, bytes data);

    // -------------------------------------------------------
    // Constructor
    // -------------------------------------------------------

    constructor() Ownable(msg.sender) {}

    /**
     * @notice Initialize the smart account with a DID hash
     * @param _didHash The Poseidon hash of the student's DID
     * @param _owner The address that controls this account (set by the system)
     */
    function initialize(bytes32 _didHash, address _owner) external {
        require(!initialized, "VoterSmartAccount: already initialized");
        initialized = true;
        didHash = _didHash;
        _transferOwnership(_owner);
        emit AccountInitialized(_didHash, _owner);
    }

    /**
     * @notice Execute a call to another contract (e.g., Voting.castVote)
     * @param target The contract to call
     * @param value ETH value to send (usually 0 for voting)
     * @param data The calldata (e.g., castVote encoded)
     */
    function execute(
        address target,
        uint256 value,
        bytes calldata data
    ) external onlyOwner returns (bytes memory) {
        (bool success, bytes memory result) = target.call{value: value}(data);
        require(success, "VoterSmartAccount: execution failed");
        emit Executed(target, value, data);
        return result;
    }

    /// @notice Allow the account to receive ETH
    receive() external payable {}
}

/**
 * @title SmartAccountFactory
 * @author Katoh Thesis Project
 * @notice Factory contract that deterministically deploys VoterSmartAccount
 *         instances based on DID hashes.
 * @dev Uses CREATE2 for deterministic addresses — given the same DID hash,
 *      the same Smart Account address is always computed.
 */
contract SmartAccountFactory {
    /// @notice Mapping from DID hash to deployed Smart Account address
    mapping(bytes32 => address) public accounts;

    /// @notice Total accounts created
    uint256 public accountCount;

    // -------------------------------------------------------
    // Events
    // -------------------------------------------------------

    event AccountCreated(bytes32 indexed didHash, address indexed account);

    // -------------------------------------------------------
    // Factory Functions
    // -------------------------------------------------------

    /**
     * @notice Deploy or retrieve a Smart Account for a given DID hash
     * @param _didHash The DID hash to associate with the account
     * @param _owner The address that will control the account
     * @return account The address of the Smart Account
     */
    function getOrCreateAccount(
        bytes32 _didHash,
        address _owner
    ) external returns (address account) {
        // If account already exists, return it
        if (accounts[_didHash] != address(0)) {
            return accounts[_didHash];
        }

        // Deploy a new Smart Account using CREATE2 for deterministic addressing
        bytes32 salt = _didHash;
        VoterSmartAccount newAccount = new VoterSmartAccount{salt: salt}();
        newAccount.initialize(_didHash, _owner);

        accounts[_didHash] = address(newAccount);
        accountCount++;

        emit AccountCreated(_didHash, address(newAccount));
        return address(newAccount);
    }

    /**
     * @notice Compute the deterministic address of a Smart Account without deploying
     * @param _didHash The DID hash to compute the address for
     * @return The predicted address
     */
    function computeAddress(bytes32 _didHash) external view returns (address) {
        bytes32 salt = _didHash;
        bytes memory bytecode = type(VoterSmartAccount).creationCode;
        bytes32 hash = keccak256(
            abi.encodePacked(bytes1(0xff), address(this), salt, keccak256(bytecode))
        );
        return address(uint160(uint256(hash)));
    }
}

contracts/VoterEligibility.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title IGroth16Verifier
 * @notice Interface for the auto-generated Groth16 verifier from snarkjs
 */
interface IGroth16Verifier {
    function verifyProof(
        uint256[2] calldata _pA,
        uint256[2][2] calldata _pB,
        uint256[2] calldata _pC,
        uint256[3] calldata _pubSignals
    ) external view returns (bool);
}

/**
 * @title VoterEligibility
 * @author Katoh Thesis Project
 * @notice Verifies student enrollment eligibility using zk-SNARK proofs and
 *         manages the set of eligible voters for an election.
 * @dev This contract:
 *   - Accepts a Groth16 proof proving a student holds valid enrollment data
 *     matching a known commitment, without revealing personal academic records.
 *   - Uses a nullifier hash to prevent a student from registering twice for the
 *     same election.
 *   - Maintains a registry of eligible DIDs that the Voting contract references.
 */
contract VoterEligibility {
    // -------------------------------------------------------
    // State
    // -------------------------------------------------------

    /// @notice The admin (university) who manages elections and enrollment commitments
    address public admin;

    /// @notice The on-chain Groth16 verifier contract (auto-generated by snarkjs)
    IGroth16Verifier public verifier;

    /// @notice The current election identifier
    uint256 public currentElectionId;

    /// @notice Whether an enrollment commitment is registered (set by admin during enrollment)
    mapping(bytes32 => bool) public enrollmentCommitments;

    /// @notice Whether a nullifier hash has been used (prevents double registration)
    mapping(bytes32 => bool) public usedNullifiers;

    /// @notice Whether a DID is marked as eligible for the current election
    mapping(bytes32 => bool) public eligibleVoters;

    /// @notice Total number of eligible voters registered for the current election
    uint256 public eligibleVoterCount;

    // -------------------------------------------------------
    // Events
    // -------------------------------------------------------

    event EnrollmentCommitmentAdded(bytes32 indexed commitment);
    event EnrollmentCommitmentRevoked(bytes32 indexed commitment);
    event VoterVerified(bytes32 indexed didHash, bytes32 indexed nullifierHash);
    event ElectionCreated(uint256 indexed electionId);

    // -------------------------------------------------------
    // Modifiers
    // -------------------------------------------------------

    modifier onlyAdmin() {
        require(msg.sender == admin, "VoterEligibility: caller is not admin");
        _;
    }

    // -------------------------------------------------------
    // Constructor
    // -------------------------------------------------------

    /**
     * @param _verifier Address of the deployed Groth16 verifier contract
     */
    constructor(address _verifier) {
        admin = msg.sender;
        verifier = IGroth16Verifier(_verifier);
    }

    // -------------------------------------------------------
    // Admin Functions
    // -------------------------------------------------------

    /**
     * @notice Start a new election. Resets eligibility state.
     * @param _electionId Unique identifier for the election
     */
    function createElection(uint256 _electionId) external onlyAdmin {
        require(_electionId > 0, "VoterEligibility: invalid election ID");
        currentElectionId = _electionId;
        eligibleVoterCount = 0;
        emit ElectionCreated(_electionId);
    }

    /**
     * @notice Register enrollment commitments (batch). Called during student enrollment.
     * @dev The commitment is Poseidon(matricNumber, departmentId, enrollmentSecret)
     * @param _commitments Array of enrollment commitments to register
     */
    function addEnrollmentCommitments(bytes32[] calldata _commitments) external onlyAdmin {
        for (uint256 i = 0; i < _commitments.length; i++) {
            enrollmentCommitments[_commitments[i]] = true;
            emit EnrollmentCommitmentAdded(_commitments[i]);
        }
    }

    /**
     * @notice Revoke an enrollment commitment (e.g., student expelled)
     * @param _commitment The commitment to revoke
     */
    function revokeEnrollmentCommitment(bytes32 _commitment) external onlyAdmin {
        enrollmentCommitments[_commitment] = false;
        emit EnrollmentCommitmentRevoked(_commitment);
    }

    // -------------------------------------------------------
    // Voter Registration (ZKP-based)
    // -------------------------------------------------------

    /**
     * @notice Verify a student's eligibility using a zk-SNARK proof and register
     *         them as an eligible voter.
     *
     * @param _pA       Groth16 proof point A
     * @param _pB       Groth16 proof point B
     * @param _pC       Groth16 proof point C
     * @param _pubSignals Public signals: [enrollmentCommitment, nullifierHash, electionId]
     * @param _didHash  Hash of the student's Decentralised Identifier
     *
     * @dev The proof demonstrates:
     *   1. The prover knows (matricNumber, departmentId, enrollmentSecret) whose
     *      Poseidon hash equals the public enrollmentCommitment.
     *   2. The nullifierHash is correctly derived from (matricNumber, electionId).
     */
    function verifyAndRegister(
        uint256[2] calldata _pA,
        uint256[2][2] calldata _pB,
        uint256[2] calldata _pC,
        uint256[3] calldata _pubSignals,
        bytes32 _didHash
    ) external {
        // Extract public signals
        bytes32 enrollmentCommitment = bytes32(_pubSignals[0]);
        bytes32 nullifierHash = bytes32(_pubSignals[1]);
        uint256 electionId = _pubSignals[2];

        // Validate election context
        require(electionId == currentElectionId, "VoterEligibility: wrong election ID");

        // Validate enrollment commitment is registered
        require(
            enrollmentCommitments[enrollmentCommitment],
            "VoterEligibility: unknown enrollment commitment"
        );

        // Prevent double registration using nullifier
        require(!usedNullifiers[nullifierHash], "VoterEligibility: already registered");

        // Prevent re-registration of the same DID
        require(!eligibleVoters[_didHash], "VoterEligibility: DID already eligible");

        // Verify the zk-SNARK proof on-chain
        bool proofValid = verifier.verifyProof(_pA, _pB, _pC, _pubSignals);
        require(proofValid, "VoterEligibility: invalid proof");

        // Mark nullifier as used and DID as eligible
        usedNullifiers[nullifierHash] = true;
        eligibleVoters[_didHash] = true;
        eligibleVoterCount++;

        emit VoterVerified(_didHash, nullifierHash);
    }

    // -------------------------------------------------------
    // View Functions
    // -------------------------------------------------------

    /**
     * @notice Check if a DID is eligible to vote
     * @param _didHash Hash of the DID to check
     * @return True if the DID is registered as eligible
     */
    function isEligible(bytes32 _didHash) external view returns (bool) {
        return eligibleVoters[_didHash];
    }
}

contracts/Voting.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./VoterEligibility.sol";

/**
 * @title Voting
 * @author Katoh Thesis Project
 * @notice Core election contract that manages candidates, enforces one-vote-per-DID,
 *         and provides public self-tallying.
 * @dev This contract:
 *   - References VoterEligibility to confirm voter eligibility before accepting votes.
 *   - Enforces the one-vote-per-DID rule: once a DID has voted, any subsequent
 *     attempt is cryptographically rejected.
 *   - Provides a public self-tallying function that anyone can call to verify results.
 *   - Implements re-entrancy guards and access control as per Kushwaha et al. (2022).
 */
contract Voting {
    // -------------------------------------------------------
    // State
    // -------------------------------------------------------

    /// @notice The admin (university election committee)
    address public admin;

    /// @notice Reference to the VoterEligibility contract
    VoterEligibility public eligibilityContract;

    /// @notice The election identifier this contract governs
    uint256 public electionId;

    /// @notice Whether the election is currently active (accepting votes)
    bool public electionActive;

    /// @notice Re-entrancy guard
    bool private _locked;

    /// @notice Candidate information
    struct Candidate {
        uint256 id;
        string name;
        string party;
        uint256 voteCount;
        bool exists;
    }

    /// @notice Mapping from candidate ID to Candidate
    mapping(uint256 => Candidate) public candidates;

    /// @notice Array of candidate IDs for iteration
    uint256[] public candidateIds;

    /// @notice Total number of candidates
    uint256 public candidateCount;

    /// @notice Whether a DID has already voted
    mapping(bytes32 => bool) public hasVoted;

    /// @notice Total votes cast
    uint256 public totalVotesCast;

    /// @notice Election start and end timestamps
    uint256 public electionStart;
    uint256 public electionEnd;

    // -------------------------------------------------------
    // Events
    // -------------------------------------------------------

    event ElectionInitialized(uint256 indexed electionId, uint256 startTime, uint256 endTime);
    event CandidateAdded(uint256 indexed candidateId, string name, string party);
    event VoteCast(bytes32 indexed didHash, uint256 indexed candidateId);
    event ElectionEnded(uint256 indexed electionId, uint256 totalVotes);

    // -------------------------------------------------------
    // Modifiers
    // -------------------------------------------------------

    modifier onlyAdmin() {
        require(msg.sender == admin, "Voting: caller is not admin");
        _;
    }

    modifier whenElectionActive() {
        require(electionActive, "Voting: election is not active");
        require(block.timestamp >= electionStart, "Voting: election has not started");
        require(block.timestamp <= electionEnd, "Voting: election has ended");
        _;
    }

    /// @notice Re-entrancy guard (Kushwaha et al., 2022 — mitigation for re-entrancy attacks)
    modifier nonReentrant() {
        require(!_locked, "Voting: re-entrant call");
        _locked = true;
        _;
        _locked = false;
    }

    // -------------------------------------------------------
    // Constructor
    // -------------------------------------------------------

    /**
     * @param _eligibilityContract Address of the deployed VoterEligibility contract
     */
    constructor(address _eligibilityContract) {
        admin = msg.sender;
        eligibilityContract = VoterEligibility(_eligibilityContract);
    }

    // -------------------------------------------------------
    // Admin Functions
    // -------------------------------------------------------

    /**
     * @notice Initialize a new election with a time window
     * @param _electionId Unique election identifier (must match VoterEligibility)
     * @param _startTime Unix timestamp when voting opens
     * @param _endTime Unix timestamp when voting closes
     */
    function initializeElection(
        uint256 _electionId,
        uint256 _startTime,
        uint256 _endTime
    ) external onlyAdmin {
        require(!electionActive, "Voting: election already active");
        require(_startTime < _endTime, "Voting: invalid time window");
        require(_electionId == eligibilityContract.currentElectionId(),
            "Voting: election ID mismatch with eligibility contract");

        electionId = _electionId;
        electionStart = _startTime;
        electionEnd = _endTime;
        electionActive = true;
        totalVotesCast = 0;

        emit ElectionInitialized(_electionId, _startTime, _endTime);
    }

    /**
     * @notice Add a candidate to the election
     * @param _candidateId Unique candidate identifier
     * @param _name Candidate's name
     * @param _party Candidate's party or affiliation
     */
    function addCandidate(
        uint256 _candidateId,
        string calldata _name,
        string calldata _party
    ) external onlyAdmin {
        require(!candidates[_candidateId].exists, "Voting: candidate already exists");

        candidates[_candidateId] = Candidate({
            id: _candidateId,
            name: _name,
            party: _party,
            voteCount: 0,
            exists: true
        });
        candidateIds.push(_candidateId);
        candidateCount++;

        emit CandidateAdded(_candidateId, _name, _party);
    }

    /**
     * @notice End the election manually (admin override)
     */
    function endElection() external onlyAdmin {
        require(electionActive, "Voting: no active election");
        electionActive = false;
        emit ElectionEnded(electionId, totalVotesCast);
    }

    // -------------------------------------------------------
    // Voting
    // -------------------------------------------------------

    /**
     * @notice Cast a vote for a candidate
     * @param _didHash Hash of the voter's Decentralised Identifier
     * @param _candidateId ID of the candidate to vote for
     *
     * @dev This function:
     *   1. Checks the DID is eligible (via VoterEligibility contract)
     *   2. Enforces one-vote-per-DID
     *   3. Records the vote
     *   4. Uses re-entrancy guard
     *
     * In the ERC-4337 flow, this is called via the EntryPoint contract on behalf
     * of the student's Smart Account, with gas sponsored by the Paymaster.
     */
    function castVote(
        bytes32 _didHash,
        uint256 _candidateId
    ) external whenElectionActive nonReentrant {
        // Verify voter eligibility via the eligibility contract
        require(
            eligibilityContract.isEligible(_didHash),
            "Voting: voter is not eligible"
        );

        // Enforce one-vote-per-DID (double-vote prevention)
        require(!hasVoted[_didHash], "Voting: already voted");

        // Verify candidate exists
        require(candidates[_candidateId].exists, "Voting: candidate does not exist");

        // Record the vote
        hasVoted[_didHash] = true;
        candidates[_candidateId].voteCount++;
        totalVotesCast++;

        emit VoteCast(_didHash, _candidateId);
    }

    // -------------------------------------------------------
    // Public Self-Tallying (anyone can verify results)
    // -------------------------------------------------------

    /**
     * @notice Get the vote count for a specific candidate
     * @param _candidateId ID of the candidate
     * @return name The candidate's name
     * @return party The candidate's party
     * @return voteCount The number of votes received
     */
    function getCandidate(uint256 _candidateId)
        external
        view
        returns (string memory name, string memory party, uint256 voteCount)
    {
        require(candidates[_candidateId].exists, "Voting: candidate does not exist");
        Candidate storage c = candidates[_candidateId];
        return (c.name, c.party, c.voteCount);
    }

    /**
     * @notice Get the full election results (self-tallying)
     * @return ids Array of candidate IDs
     * @return names Array of candidate names
     * @return parties Array of candidate parties
     * @return voteCounts Array of vote counts
     */
    function getResults()
        external
        view
        returns (
            uint256[] memory ids,
            string[] memory names,
            string[] memory parties,
            uint256[] memory voteCounts
        )
    {
        uint256 len = candidateIds.length;
        ids = new uint256[](len);
        names = new string[](len);
        parties = new string[](len);
        voteCounts = new uint256[](len);

        for (uint256 i = 0; i < len; i++) {
            Candidate storage c = candidates[candidateIds[i]];
            ids[i] = c.id;
            names[i] = c.name;
            parties[i] = c.party;
            voteCounts[i] = c.voteCount;
        }
    }

    /**
     * @notice Get the winning candidate (self-tallying)
     * @return winnerId The ID of the candidate with the most votes
     * @return winnerName The name of the winning candidate
     * @return winnerVotes The vote count of the winner
     */
    function getWinner()
        external
        view
        returns (uint256 winnerId, string memory winnerName, uint256 winnerVotes)
    {
        require(candidateIds.length > 0, "Voting: no candidates");

        uint256 maxVotes = 0;
        uint256 winIdx = 0;

        for (uint256 i = 0; i < candidateIds.length; i++) {
            if (candidates[candidateIds[i]].voteCount > maxVotes) {
                maxVotes = candidates[candidateIds[i]].voteCount;
                winIdx = i;
            }
        }

        Candidate storage w = candidates[candidateIds[winIdx]];
        return (w.id, w.name, w.voteCount);
    }

    /**
     * @notice Check whether a given DID has voted
     * @param _didHash Hash of the DID to check
     * @return True if the DID has already cast a vote
     */
    function hasVoterVoted(bytes32 _didHash) external view returns (bool) {
        return hasVoted[_didHash];
    }
}

contracts/VotingPaymaster.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title VotingPaymaster
 * @author Katoh Thesis Project
 * @notice A simplified ERC-4337 Paymaster that sponsors gas fees for student voters.
 * @dev In the ERC-4337 standard, a Paymaster pays gas fees on behalf of users,
 *      removing the need for students to hold ETH or any cryptocurrency.
 *
 *      This is a simplified implementation for the thesis prototype. In production,
 *      it would extend the BasePaymaster from @account-abstraction/contracts.
 *      The university pre-funds this contract, and it approves gas sponsorship
 *      for all voting-related UserOperations.
 */

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @notice Minimal interface for the ERC-4337 EntryPoint
 */
interface IEntryPoint {
    struct UserOperation {
        address sender;
        uint256 nonce;
        bytes initCode;
        bytes callData;
        uint256 callGasLimit;
        uint256 verificationGasLimit;
        uint256 preVerificationGas;
        uint256 maxFeePerGas;
        uint256 maxPriorityFeePerGas;
        bytes paymasterAndData;
        bytes signature;
    }

    function handleOps(UserOperation[] calldata ops, address payable beneficiary) external;
    function depositTo(address account) external payable;
    function balanceOf(address account) external view returns (uint256);
}

contract VotingPaymaster is Ownable {
    IEntryPoint public immutable entryPoint;

    /// @notice Address of the Voting contract — only operations targeting this are sponsored
    address public votingContract;

    /// @notice Total gas sponsored (for metrics / thesis evaluation)
    uint256 public totalGasSponsored;
    uint256 public totalOperationsSponsored;

    // -------------------------------------------------------
    // Events
    // -------------------------------------------------------

    event Deposited(address indexed from, uint256 amount);
    event GasSponsored(address indexed sender, uint256 gasUsed);
    event VotingContractUpdated(address indexed newVotingContract);

    // -------------------------------------------------------
    // Constructor
    // -------------------------------------------------------

    /**
     * @param _entryPoint Address of the ERC-4337 EntryPoint singleton
     * @param _votingContract Address of the Voting contract to sponsor
     */
    constructor(address _entryPoint, address _votingContract) Ownable(msg.sender) {
        entryPoint = IEntryPoint(_entryPoint);
        votingContract = _votingContract;
    }

    // -------------------------------------------------------
    // Paymaster Logic
    // -------------------------------------------------------

    /**
     * @notice Validate whether a UserOperation should be sponsored
     * @dev In production ERC-4337, this would be called by the EntryPoint.
     *      For the thesis prototype, this simulates the validation logic.
     * @param userOp The UserOperation to validate
     * @return valid Whether the operation is approved for sponsorship
     */
    function validatePaymasterUserOp(
        IEntryPoint.UserOperation calldata userOp
    ) external view returns (bool valid) {
        // Only sponsor operations targeting the voting contract
        // In the real flow, userOp.sender is the Smart Account, and
        // userOp.callData contains the call to the Voting contract
        return userOp.sender != address(0) && votingContract != address(0);
    }

    /**
     * @notice Record gas sponsorship (called after successful operation)
     * @param sender The Smart Account address
     * @param gasUsed Amount of gas consumed
     */
    function recordSponsorship(address sender, uint256 gasUsed) external {
        totalGasSponsored += gasUsed;
        totalOperationsSponsored++;
        emit GasSponsored(sender, gasUsed);
    }

    // -------------------------------------------------------
    // Admin Functions
    // -------------------------------------------------------

    /**
     * @notice Deposit ETH to the EntryPoint to fund gas sponsorship
     */
    function deposit() external payable onlyOwner {
        entryPoint.depositTo{value: msg.value}(address(this));
        emit Deposited(msg.sender, msg.value);
    }

    /**
     * @notice Update the voting contract address
     * @param _votingContract New voting contract address
     */
    function setVotingContract(address _votingContract) external onlyOwner {
        votingContract = _votingContract;
        emit VotingContractUpdated(_votingContract);
    }

    /**
     * @notice Check the Paymaster's balance at the EntryPoint
     * @return The balance available for sponsorship
     */
    function getDeposit() external view returns (uint256) {
        return entryPoint.balanceOf(address(this));
    }

    /// @notice Allow the contract to receive ETH
    receive() external payable {}
}

